-- Neighborhood Engagement Hub - Production Patches
-- Stack incremental fixes here as issues are found during production review.
BEGIN;

-- Fake admin JWT context for managed PostgreSQL (no true superuser)
SET LOCAL request.jwt.claims = '{"sub":"init-script","realm_access":{"roles":["admin"]}}';
SET LOCAL search_path = public, metadata, postgis, pg_temp;

-- ============================================================================
-- 1. Genesee County Parcel ID domain type
--    Stores the canonical 12-digit form (e.g. 254014377017).
--    Display format: CC-TT-SS-BBB-PPP (county-city-section-block-parcel).
--    This format is Genesee County-specific — no US national standard exists
--    for parcel IDs (each county designs its own numbering scheme).
-- ============================================================================

-- 1a. Domain: exactly 12 digits
CREATE DOMAIN public.genesee_parcel_id AS VARCHAR(12)
  CHECK (VALUE ~ '^\d{12}$');

COMMENT ON DOMAIN public.genesee_parcel_id IS
  'Genesee County parcel ID. 12 digits: CC(county)-TT(city)-SS(section)-BBB(block)-PPP(parcel). Stored without hyphens.';

-- 1b. Format for display: 25-40-14-377-017
CREATE OR REPLACE FUNCTION public.format_parcel_id(p_id genesee_parcel_id)
RETURNS TEXT
LANGUAGE sql IMMUTABLE STRICT
AS $$
  SELECT
    substring(p_id, 1, 2) || '-' ||
    substring(p_id, 3, 2) || '-' ||
    substring(p_id, 5, 2) || '-' ||
    substring(p_id, 7, 3) || '-' ||
    substring(p_id, 10, 3);
$$;

COMMENT ON FUNCTION public.format_parcel_id(genesee_parcel_id) IS
  'Formats a 12-digit Genesee County parcel ID as CC-TT-SS-BBB-PPP.';

-- 1c. Search tokens for full-text search (like phone_search_tokens)
--     Produces fragments so users can search by:
--       Compound:  254014377017 (full), 4014377017 (GCLB), 377017 (block+parcel)
--       Segments:  25 (county), 40 (city), 14 (section), 377 (block), 017 (parcel)
CREATE OR REPLACE FUNCTION public.parcel_search_tokens(p_id genesee_parcel_id)
RETURNS TEXT
LANGUAGE sql IMMUTABLE STRICT
AS $$
  SELECT
    p_id || ' ' ||                             -- full 12:      254014377017
    substring(p_id, 3) || ' ' ||               -- no county:    4014377017
    substring(p_id, 7) || ' ' ||               -- block+parcel: 377017
    substring(p_id, 1, 2) || ' ' ||            -- CC county:    25
    substring(p_id, 3, 2) || ' ' ||            -- TT city:      40
    substring(p_id, 5, 2) || ' ' ||            -- SS section:   14
    substring(p_id, 7, 3) || ' ' ||            -- BBB block:    377
    substring(p_id, 10, 3);                    -- PPP parcel:   017
$$;

COMMENT ON FUNCTION public.parcel_search_tokens(genesee_parcel_id) IS
  'Pre-computes searchable parcel ID fragments for GIN-indexed tsvector lookup. Similar to phone_search_tokens.';

-- ============================================================================
-- 2. Convert parcels.parcel_number to genesee_parcel_id
-- ============================================================================

-- 2a. Drop the generated tsvector column (it references parcel_number directly)
ALTER TABLE parcels DROP COLUMN IF EXISTS civic_os_text_search;

-- 2b. Strip hyphens from existing data
UPDATE parcels SET parcel_number = REPLACE(parcel_number, '-', '')
WHERE parcel_number LIKE '%-%';

-- 2c. Convert column type to domain
ALTER TABLE parcels ALTER COLUMN parcel_number TYPE genesee_parcel_id;

-- 2d. Recreate tsvector with parcel_search_tokens
ALTER TABLE parcels ADD COLUMN civic_os_text_search tsvector GENERATED ALWAYS AS (
    to_tsvector('english',
        coalesce(display_name, '') || ' ' ||
        coalesce(parcel_search_tokens(parcel_number), '') || ' ' ||
        coalesce(prop_street, '') || ' ' ||
        coalesce(prop_zip, ''))
) STORED;

CREATE INDEX IF NOT EXISTS idx_parcels_text_search ON parcels USING GIN(civic_os_text_search);

-- 2e. Add formatted display column (generated from domain)
ALTER TABLE parcels ADD COLUMN parcel_number_formatted TEXT GENERATED ALWAYS AS (
    format_parcel_id(parcel_number)
) STORED;

-- 2f. Metadata: formatted column on list/detail, raw column on create/edit
INSERT INTO metadata.properties (table_name, column_name, display_name, sort_order, show_on_list, show_on_detail, show_on_create, show_on_edit, filterable)
VALUES
  ('parcels', 'parcel_number',           'Parcel Number', 2, false, false, true,  true,  false),
  ('parcels', 'parcel_number_formatted', 'Parcel Number', 2, true,  true,  false, false, false)
ON CONFLICT (table_name, column_name) DO UPDATE
SET display_name = EXCLUDED.display_name,
    sort_order = EXCLUDED.sort_order,
    show_on_list = EXCLUDED.show_on_list,
    show_on_detail = EXCLUDED.show_on_detail,
    show_on_create = EXCLUDED.show_on_create,
    show_on_edit = EXCLUDED.show_on_edit,
    filterable = EXCLUDED.filterable;

-- ============================================================================
-- 3. Land Bank Ownership flag
--    GCLB publishes a CSV of owned parcel IDs (10-digit, no county prefix).
--    With the new domain, mapping is: SUBSTRING(parcel_number FROM 3) = csv_id
--    Source: "GCLB Propert List as of 5.13.26.csv" (12133 parcels)
-- ============================================================================

-- 3a. Add the column (before RPC in section 4 references it)
ALTER TABLE parcels ADD COLUMN IF NOT EXISTS land_bank_owned BOOLEAN NOT NULL DEFAULT FALSE;
CREATE INDEX IF NOT EXISTS idx_parcels_land_bank_owned ON parcels(land_bank_owned) WHERE land_bank_owned;

-- 3b. Property metadata
INSERT INTO metadata.properties (table_name, column_name, display_name, sort_order, show_on_list, show_on_create, show_on_edit, show_on_detail, filterable)
VALUES ('parcels', 'land_bank_owned', 'Land Bank Owned', 13, true, false, false, true, true)
ON CONFLICT (table_name, column_name) DO UPDATE
SET display_name = EXCLUDED.display_name,
    sort_order = EXCLUDED.sort_order,
    show_on_list = EXCLUDED.show_on_list,
    show_on_create = EXCLUDED.show_on_create,
    show_on_edit = EXCLUDED.show_on_edit,
    show_on_detail = EXCLUDED.show_on_detail,
    filterable = EXCLUDED.filterable;

-- 3c. Enrichment RPC — accepts array of 10-digit GCLB parcel IDs.
CREATE OR REPLACE FUNCTION public.enrich_parcels_land_bank(p_parcel_ids TEXT[])
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, metadata, pg_temp
AS $$
DECLARE
  v_marked INT;
  v_cleared INT;
BEGIN
  IF NOT public.has_permission('parcels', 'update') THEN
    RAISE EXCEPTION 'Permission denied: parcels update required'
      USING ERRCODE = '42501';
  END IF;

  -- Mark matching parcels as land-bank-owned
  UPDATE parcels
  SET land_bank_owned = TRUE
  WHERE NOT land_bank_owned
    AND SUBSTRING(parcel_number FROM 3) = ANY(p_parcel_ids);

  GET DIAGNOSTICS v_marked = ROW_COUNT;

  -- Clear parcels no longer on the list
  UPDATE parcels
  SET land_bank_owned = FALSE
  WHERE land_bank_owned
    AND SUBSTRING(parcel_number FROM 3) != ALL(p_parcel_ids);

  GET DIAGNOSTICS v_cleared = ROW_COUNT;

  RETURN jsonb_build_object(
    'success', true,
    'marked', v_marked,
    'cleared', v_cleared,
    'message', format('%s parcels marked land-bank-owned, %s cleared', v_marked, v_cleared)
  );
END;
$$;

COMMENT ON FUNCTION public.enrich_parcels_land_bank(TEXT[]) IS
  'Bulk-update land_bank_owned flag on parcels. Accepts array of 10-digit GCLB parcel IDs (county prefix stripped). Clears flag on parcels not in the list.';

GRANT EXECUTE ON FUNCTION public.enrich_parcels_land_bank(TEXT[]) TO authenticated;

