-- ============================================================================
-- 4. Update eligible parcels RPC — add LMI + land bank filters
--    Tool reservations should only offer parcels that are:
--      - LMI qualified (eligible for CDBG-funded tool lending)
--      - NOT land-bank-owned (land bank has its own maintenance programs)
--    Retains the existing eligibility category filter from script 05.
-- ============================================================================

CREATE OR REPLACE FUNCTION public.get_eligible_parcels_new(p_id TEXT DEFAULT NULL, p_depends_on JSONB DEFAULT '{}')
RETURNS TABLE (id INT, display_name TEXT)
LANGUAGE SQL STABLE AS $$
    SELECT p.id, p.display_name::TEXT
    FROM parcels p
    WHERE p.lmi_status = (
        SELECT c.id FROM metadata.categories c
        WHERE c.entity_type = 'lmi_status'
        AND c.category_key = 'lmi_qualified'
    )
    AND NOT p.land_bank_owned
    ORDER BY p.display_name;
$$;

-- ============================================================================
-- 5. Make property_class filterable on list page
-- ============================================================================

INSERT INTO metadata.properties (table_name, column_name, display_name, filterable)
VALUES ('parcels', 'property_class', 'Property Class', true)
ON CONFLICT (table_name, column_name) DO UPDATE
SET filterable = EXCLUDED.filterable;

COMMIT;

-- PostgREST schema reload (new columns, domain type, updated RPCs)
NOTIFY pgrst, 'reload schema';
